class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


class CheckoutError(Exception):
    pass


class ValidationError(CheckoutError):
    pass


class PermissionError(CheckoutError):
    pass


class PaymentError(CheckoutError):
    pass


class CartItem:
    def __init__(self, product_id: str, name: str, price: Decimal, quantity: int, max_quantity: int = 100):
        if quantity <= 0:
            raise ValidationError("Quantity must be positive")
        if quantity > max_quantity:
            raise ValidationError(f"Quantity exceeds maximum allowed: {max_quantity}")
        if price < 0:
            raise ValidationError("Price cannot be negative")
        
        self.product_id = str(product_id)
        self.name = str(name)
        self.price = Decimal(str(price))
        self.quantity = int(quantity)
        self.max_quantity = max_quantity

    def get_subtotal(self) -> Decimal:
        return self.price * self.quantity


class DiscountCode:
    def __init__(
        self,
        code: str,
        discount_type: DiscountType,
        value: Decimal,
        min_tier: UserTier,
        min_purchase: Decimal = Decimal('0'),
        max_discount: Optional[Decimal] = None,
        is_active: bool = True
    ):
        self.code = str(code).upper()
        self.discount_type = discount_type
        self.value = Decimal(str(value))
        self.min_tier = min_tier
        self.min_purchase = Decimal(str(min_purchase))
        self.max_discount = Decimal(str(max_discount)) if max_discount else None
        self.is_active = is_active

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        if not self.is_active:
            return Decimal('0')
        
        if subtotal < self.min_purchase:
            return Decimal('0')
        
        if self.discount_type == DiscountType.PERCENTAGE:
            discount = subtotal * (self.value / Decimal('100'))
        else:
            discount = self.value
        
        if self.max_discount and discount > self.max_discount:
            discount = self.max_discount
        
        return discount.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)


class User:
    def __init__(self, user_id: str, tier: UserTier, email: str):
        self.user_id = str(user_id)
        self.tier = tier
        self.email = str(email)


class TaxCalculator:
    def __init__(self, tax_rate: Decimal):
        self.tax_rate = Decimal(str(tax_rate))
    
    def calculate_tax(self, taxable_amount: Decimal) -> Decimal:
        if taxable_amount < 0:
            raise ValidationError("Taxable amount cannot be negative")
        tax = taxable_amount * self.tax_rate
        return tax.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)


class PaymentProcessor:
    def __init__(self, secret_key: str):
        self.secret_key = secret_key.encode()
    
    def process_payment(
        self,
        amount: Decimal,
        payment_method: str,
        user: User
    ) -> Dict:
        if amount <= 0:
            raise PaymentError("Payment amount must be positive")
        
        payment_method_clean = str(payment_method).strip()
        if not payment_method_clean:
            raise PaymentError("Payment method is required")
        
        transaction_id = secrets.token_urlsafe(32)
        
        signature_data = f"{transaction_id}:{user.user_id}:{amount}:{payment_method_clean}"
        signature = hmac.new(
            self.secret_key,
            signature_data.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return {
            'transaction_id': transaction_id,
            'amount': amount,
            'status': 'completed',
            'signature': signature,
            'timestamp': datetime.utcnow().isoformat()
        }


class Order:
    def __init__(
        self,
        order_id: str,
        user_id: str,
        items: List[CartItem],
        subtotal: Decimal,
        discount: Decimal,
        tax: Decimal,
        total: Decimal,
        payment_info: Dict,
        discount_code: Optional[str] = None
    ):
        self.order_id = order_id
        self.user_id = user_id
        self.items = items
        self.subtotal = subtotal
        self.discount = discount
        self.tax = tax
        self.total = total
        self.payment_info = payment_info
        self.discount_code = discount_code
        self.created_at = datetime.utcnow().isoformat()
    
    def to_dict(self) -> Dict:
        return {
            'order_id': self.order_id,
            'user_id': self.user_id,
            'items': [
                {
                    'product_id': item.product_id,
                    'name': item.name,
                    'price': str(item.price),
                    'quantity': item.quantity,
                    'subtotal': str(item.get_subtotal())
                }
                for item in self.items
            ],
            'subtotal': str(self.subtotal),
            'discount': str(self.discount),
            'tax': str(self.tax),
            'total': str(self.total),
            'discount_code': self.discount_code,
            'payment_info': {
                'transaction_id': self.payment_info['transaction_id'],
                'status': self.payment_info['status'],
                'timestamp': self.payment_info['timestamp']
            },
            'created_at': self.created_at
        }


class CheckoutProcessor:
    TIER_HIERARCHY = {
        UserTier.GUEST: 0,
        UserTier.BASIC: 1,
        UserTier.PREMIUM: 2,
        UserTier.ADMIN: 3
    }
    
    def __init__(
        self,
        discount_codes: Dict[str, DiscountCode],
        tax_calculator: TaxCalculator,
        payment_processor: PaymentProcessor
    ):
        self.discount_codes = discount_codes
        self.tax_calculator = tax_calculator
        self.payment_processor = payment_processor
    
    def validate_cart_items(self, items: List[CartItem]) -> Tuple[List[CartItem], Decimal]:
        if not items:
            raise ValidationError("Cart is empty")
        
        if len(items) > 100:
            raise ValidationError("Too many items in cart")
        
        validated_items = []
        subtotal = Decimal('0')
        
        seen_products = set()
        for item in items:
            if not isinstance(item, CartItem):
                raise ValidationError("Invalid cart item")
            
            if item.product_id in seen_products:
                raise ValidationError(f"Duplicate product in cart: {item.product_id}")
            seen_products.add(item.product_id)
            
            if not item.product_id or not item.name:
                raise ValidationError("Invalid product data")
            
            validated_items.append(item)
            subtotal += item.get_subtotal()
        
        return validated_items, subtotal
    
    def validate_and_apply_discount(
        self,
        discount_code: Optional[str],
        subtotal: Decimal,
        user: User
    ) -> Tuple[Decimal, Optional[str]]:
        if not discount_code:
            return Decimal('0'), None
        
        code_upper = str(discount_code).strip().upper()
        
        if not re.match(r'^[A-Z0-9_-]{3,20}$', code_upper):
            raise ValidationError("Invalid discount code format")
        
        if code_upper not in self.discount_codes:
            raise ValidationError("Invalid discount code")
        
        discount_obj = self.discount_codes[code_upper]
        
        if not discount_obj.is_active:
            raise ValidationError("Discount code is not active")
        
        user_tier_level = self.TIER_HIERARCHY.get(user.tier, 0)
        required_tier_level = self.TIER_HIERARCHY.get(discount_obj.min_tier, 0)
        
        if user_tier_level < required_tier_level:
            raise PermissionError(
                f"Insufficient permissions to use this discount code. "
                f"Required tier: {discount_obj.min_tier.value}"
            )
        
        discount_amount = discount_obj.calculate_discount(subtotal)
        
        if discount_amount > subtotal:
            discount_amount = subtotal
        
        return discount_amount, code_upper
    
    def calculate_tax_step(self, subtotal: Decimal, discount: Decimal) -> Decimal:
        taxable_amount = subtotal - discount
        
        if taxable_amount < 0:
            taxable_amount = Decimal('0')
        
        return self.tax_calculator.calculate_tax(taxable_amount)
    
    def process_payment_step(
        self,
        total: Decimal,
        payment_method: str,
        user: User
    ) -> Dict:
        if total < 0:
            raise PaymentError("Total amount cannot be negative")
        
        if total == 0:
            return {
                'transaction_id': 'FREE_ORDER',
                'amount': Decimal('0'),
                'status': 'completed',
                'signature': 'N/A',
                'timestamp': datetime.utcnow().isoformat()
            }
        
        return self.payment_processor.process_payment(total, payment_method, user)
    
    def create_order_record(
        self,
        user: User,
        items: List[CartItem],
        subtotal: Decimal,
        discount: Decimal,
        tax: Decimal,
        total: Decimal,
        payment_info: Dict,
        discount_code: Optional[str]
    ) -> Order:
        order_id = secrets.token_urlsafe(16)
        
        order = Order(
            order_id=order_id,
            user_id=user.user_id,
            items=items,
            subtotal=subtotal,
            discount=discount,
            tax=tax,
            total=total,
            payment_info=payment_info,
            discount_code=discount_code
        )
        
        return order
    
    def process_checkout(
        self,
        user: User,
        cart_items: List[CartItem],
        discount_code: Optional[str],
        payment_method: str
    ) -> Order:
        validated_items, subtotal = self.validate_cart_items(cart_items)
        
        discount, applied_code = self.validate_and_apply_discount(
            discount_code,
            subtotal,
            user
        )
        
        tax = self.calculate_tax_step(subtotal, discount)
        
        total = subtotal - discount + tax
        total = total.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)
        
        payment_info = self.process_payment_step(total, payment_method, user)
        
        order = self.create_order_record(
            user=user,
            items=validated_items,
            subtotal=subtotal,
            discount=discount,
            tax=tax,
            total=total,
            payment_info=payment_info,
            discount_code=applied_code
        )
        
        return order


